import { useEffect, useState } from 'react';
import { useParams, Link } from 'react-router-dom';
import { MapPin, Phone, MessageCircle, User, Calendar, Eye, ShieldCheck, Tag } from 'lucide-react';
import { fetchApi } from '../utils/api';
import './AdDetail.css';

export const AdDetail = () => {
    const { id } = useParams();
    const [ad, setAd] = useState<any>(null);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        fetchApi(`/ads/${id}`).then(data => {
            if (data) setAd(data);
            setLoading(false);
        }).catch(() => setLoading(false));
    }, [id]);

    if (loading) return <div className="container mt-4 loading-spinner">Carregando anúncio...</div>;
    if (!ad) return <div className="container mt-4 empty-state">Anúncio não encontrado.</div>;

    const formattedPrice = new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(ad.price);
    const date = new Date(ad.created_at).toLocaleDateString();

    return (
        <div className="ad-detail-page container">
            <div className="ad-header">
                <Link to="/explore" className="back-link">&larr; Voltar para explorar</Link>
                <div className="ad-category-badge">{ad.category.name}</div>
            </div>

            <div className="ad-content">
                <div className="ad-main">
                    <div className="ad-gallery">
                        {ad.images && ad.images.length > 0 ? (
                            <img src={`http://localhost:5000${ad.images[0]}`} alt={ad.title} className="ad-hero-img" />
                        ) : (
                            <div className="ad-placeholder-img">Sem imagem</div>
                        )}
                        {ad.images && ad.images.length > 1 && (
                            <div className="ad-thumbnails">
                                {ad.images.map((img: string, idx: number) => (
                                    <img key={idx} src={`http://localhost:5000${img}`} alt="Thumbnail" />
                                ))}
                            </div>
                        )}
                    </div>

                    <div className="ad-info-section box-card">
                        <h1 className="ad-title">{ad.title}</h1>
                        <p className="ad-price">{formattedPrice}</p>

                        <div className="ad-meta">
                            <span className="meta-item"><MapPin size={16} /> {ad.city}</span>
                            <span className="meta-item"><Calendar size={16} /> Publicado em {date}</span>
                            <span className="meta-item"><Eye size={16} /> {ad.views} visualizações</span>
                            <span className="meta-item"><Tag size={16} /> {ad.type === 'PRODUCT' ? 'Produto' : 'Serviço'}</span>
                        </div>

                        <div className="ad-description">
                            <h3>Descrição</h3>
                            <p>{ad.description}</p>
                        </div>
                    </div>
                </div>

                <div className="ad-sidebar">
                    <div className="seller-card box-card">
                        <h3>Informações do Anunciante</h3>
                        <div className="seller-profile">
                            <div className="seller-avatar">
                                {ad.user.profile_picture ? (
                                    <img src={`http://localhost:5000${ad.user.profile_picture}`} alt="Avatar" />
                                ) : (
                                    <User size={32} />
                                )}
                            </div>
                            <div>
                                <h4 className="seller-name">{ad.user.name}</h4>
                                <span className="seller-badge"><ShieldCheck size={14} /> Usuário verificado</span>
                            </div>
                        </div>

                        <div className="seller-actions">
                            <button className="btn btn-primary btn-block action-btn">
                                <MessageCircle size={20} /> Chat
                            </button>
                            {ad.user.phone && (
                                <a href={`https://wa.me/55${ad.user.phone.replace(/\D/g, '')}`} target="_blank" rel="noreferrer" className="btn btn-outline btn-block action-btn whatsapp-btn">
                                    <Phone size={20} /> WhatsApp
                                </a>
                            )}
                        </div>

                        <div className="safety-tips">
                            <h4>Dicas de Segurança</h4>
                            <ul>
                                <li>Não pague antecipadamente.</li>
                                <li>Encontre-se em local público e movimentado.</li>
                                <li>Verifique o produto pessoalmente.</li>
                            </ul>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    );
};

import { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { Upload, X } from 'lucide-react';
import { fetchApi } from '../utils/api';
import './CreateAd.css';

export const CreateAd = () => {
    const navigate = useNavigate();
    const [title, setTitle] = useState('');
    const [description, setDescription] = useState('');
    const [price, setPrice] = useState('');
    const [type, setType] = useState('PRODUCT');
    const [city, setCity] = useState('');
    const [categoryId, setCategoryId] = useState('');
    const [categories, setCategories] = useState([]);
    const [images, setImages] = useState<File[]>([]);
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState('');

    useEffect(() => {
        // Load categories
        fetchApi('/categories').then(data => {
            if (data) setCategories(data);
            if (data && data.length > 0) setCategoryId(data[0].id);
        });
    }, []);

    const handleImageChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        if (e.target.files) {
            const filesArray = Array.from(e.target.files);
            setImages(prev => [...prev, ...filesArray].slice(0, 5)); // max 5 images
        }
    };

    const removeImage = (index: number) => {
        setImages(prev => prev.filter((_, i) => i !== index));
    };

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setError('');
        setLoading(true);

        const formData = new FormData();
        formData.append('title', title);
        formData.append('description', description);
        formData.append('price', price);
        formData.append('type', type);
        formData.append('city', city);
        formData.append('category_id', categoryId);

        images.forEach(img => formData.append('images', img));

        try {
            await fetchApi('/ads', {
                method: 'POST',
                body: formData // No custom headers, fetchApi handles FormData correctly by NOT setting Content-Type
            });
            navigate('/dashboard');
        } catch (err: any) {
            setError(err.message || 'Erro ao criar anúncio');
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className="create-ad-page container">
            <div className="form-card box-card">
                <h1 className="page-title">Criar Novo Anúncio</h1>
                <p className="page-subtitle">Preencha os detalhes para anunciar seu produto ou serviço.</p>

                {error && <div className="error-message">{error}</div>}

                <form onSubmit={handleSubmit} className="ad-form">
                    <div className="image-upload-section">
                        <label className="upload-label">
                            <Upload size={32} />
                            <span>Adicione fotos (Máx 5)</span>
                            <input
                                type="file"
                                multiple
                                accept="image/*"
                                onChange={handleImageChange}
                                hidden
                            />
                        </label>

                        {images.length > 0 && (
                            <div className="image-preview-container">
                                {images.map((img, idx) => (
                                    <div key={idx} className="image-preview">
                                        <img src={URL.createObjectURL(img)} alt="Preview" />
                                        <button type="button" onClick={() => removeImage(idx)} className="remove-img-btn">
                                            <X size={16} />
                                        </button>
                                    </div>
                                ))}
                            </div>
                        )}
                    </div>

                    <div className="form-grid">
                        <div className="form-group span-2">
                            <label>Título do Anúncio</label>
                            <input type="text" className="input" value={title} onChange={e => setTitle(e.target.value)} required />
                        </div>

                        <div className="form-group">
                            <label>Categoria</label>
                            <select className="input" value={categoryId} onChange={e => setCategoryId(e.target.value)} required>
                                {categories.map((cat: any) => (
                                    <option key={cat.id} value={cat.id}>{cat.name}</option>
                                ))}
                            </select>
                        </div>

                        <div className="form-group">
                            <label>Tipo</label>
                            <select className="input" value={type} onChange={e => setType(e.target.value)} required>
                                <option value="PRODUCT">Produto</option>
                                <option value="SERVICE">Serviço</option>
                            </select>
                        </div>

                        <div className="form-group">
                            <label>Preço (R$)</label>
                            <input type="number" step="0.01" className="input" value={price} onChange={e => setPrice(e.target.value)} required />
                        </div>

                        <div className="form-group">
                            <label>Cidade</label>
                            <input type="text" className="input" value={city} onChange={e => setCity(e.target.value)} required />
                        </div>

                        <div className="form-group span-2">
                            <label>Descrição Detalhada</label>
                            <textarea
                                className="input"
                                rows={6}
                                value={description}
                                onChange={e => setDescription(e.target.value)}
                                required
                            />
                        </div>
                    </div>

                    <button type="submit" className="btn btn-primary submit-btn" disabled={loading}>
                        {loading ? 'Publicando...' : 'Publicar Anúncio'}
                    </button>
                </form>
            </div>
        </div>
    );
};

import { useState, useEffect } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { Trash2, Plus, ExternalLink, MapPin } from 'lucide-react';
import { fetchApi } from '../utils/api';
import { useAuthStore } from '../store/authStore';
import './Dashboard.css';

export const Dashboard = () => {
    const { user } = useAuthStore();
    const navigate = useNavigate();
    const [myAds, setMyAds] = useState([]);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        if (!user) {
            navigate('/login');
            return;
        }

        loadMyAds();
    }, [user, navigate]);

    const loadMyAds = async () => {
        setLoading(true);
        try {
            const data = await fetchApi(`/ads?user_id=${user?.id}`);
            if (data) setMyAds(data);
        } catch (error) {
            console.error(error);
        } finally {
            setLoading(false);
        }
    };

    const handleDelete = async (adId: string) => {
        if (!confirm('Tem certeza que deseja excluir este anúncio?')) return;
        try {
            await fetchApi(`/ads/${adId}`, { method: 'DELETE' });
            loadMyAds();
        } catch (error) {
            alert('Erro ao excluir o anúncio');
        }
    };

    if (loading) return <div className="container mt-4 loading-spinner">Carregando seus anúncios...</div>;

    return (
        <div className="dashboard-page container">
            <div className="dashboard-header">
                <div>
                    <h1 className="page-title">Meu Painel</h1>
                    <p className="page-subtitle">Gerencie seus anúncios e informações.</p>
                </div>
                <Link to="/create-ad" className="btn btn-primary d-flex align-center gap-2">
                    <Plus size={20} /> Novo Anúncio
                </Link>
            </div>

            <div className="dashboard-stats">
                <div className="stat-card box-card">
                    <h3>Total de Anúncios</h3>
                    <p className="stat-number">{myAds.length}</p>
                </div>
                <div className="stat-card box-card">
                    <h3>Visualizações</h3>
                    <p className="stat-number">
                        {myAds.reduce((acc: number, curr: any) => acc + (curr.views || 0), 0)}
                    </p>
                </div>
            </div>

            <div className="dashboard-ads box-card">
                <h2 className="section-title">Meus Anúncios</h2>

                {myAds.length > 0 ? (
                    <div className="ad-list">
                        {myAds.map((ad: any) => (
                            <div key={ad.id} className="ad-list-item">
                                <div className="ad-item-img">
                                    {ad.images && ad.images.length > 0 ? (
                                        <img src={`http://localhost:5000${ad.images[0]}`} alt={ad.title} />
                                    ) : (
                                        <div className="placeholder">Sem foto</div>
                                    )}
                                </div>
                                <div className="ad-item-info">
                                    <Link to={`/ad/${ad.id}`} className="ad-item-title">{ad.title}</Link>
                                    <p className="ad-item-price">
                                        {new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(ad.price)}
                                    </p>
                                    <span className="ad-item-meta"><MapPin size={14} /> {ad.city}</span>
                                    <div className="ad-status-badge">
                                        {ad.status === 'ACTIVE' ? 'Ativo' : ad.status}
                                    </div>
                                </div>
                                <div className="ad-item-actions">
                                    <Link to={`/ad/${ad.id}`} className="btn-icon" title="Ver Anúncio"><ExternalLink size={20} /></Link>
                                    <button onClick={() => handleDelete(ad.id)} className="btn-icon text-danger" title="Excluir">
                                        <Trash2 size={20} />
                                    </button>
                                </div>
                            </div>
                        ))}
                    </div>
                ) : (
                    <div className="empty-state">
                        <p>Você ainda não tem anúncios publicados.</p>
                        <Link to="/create-ad" className="btn btn-primary mt-2">Começar a Vender</Link>
                    </div>
                )}
            </div>
        </div>
    );
};

import { useState, useEffect } from 'react';
import { useSearchParams } from 'react-router-dom';
import { Search, MapPin, Tag } from 'lucide-react';
import { fetchApi } from '../utils/api';
import { AdCard } from '../components/AdCard';
import './Explore.css';

export const Explore = () => {
    const [searchParams, setSearchParams] = useSearchParams();
    const [ads, setAds] = useState([]);
    const [loading, setLoading] = useState(true);

    const q = searchParams.get('q') || '';
    const city = searchParams.get('city') || '';
    const category = searchParams.get('category') || '';
    const type = searchParams.get('type') || '';

    const handleSearch = (e: React.FormEvent) => {
        e.preventDefault();
        loadAds();
    };

    const loadAds = async () => {
        setLoading(true);
        const query = new URLSearchParams({ search: q, city, category, type }).toString();
        const data = await fetchApi(`/ads?${query}`);
        if (data) setAds(data);
        setLoading(false);
    };

    useEffect(() => {
        loadAds();
    }, [q, city, category, type]);

    return (
        <div className="explore-page container">
            <h1 className="page-title">Explorar Anúncios</h1>

            <form onSubmit={handleSearch} className="search-filters">
                <div className="filter-group">
                    <Search className="filter-icon" />
                    <input
                        type="text"
                        placeholder="O que você procura?"
                        value={q}
                        onChange={(e) => setSearchParams(prev => { prev.set('q', e.target.value); return prev; })}
                        className="input"
                    />
                </div>

                <div className="filter-group">
                    <MapPin className="filter-icon" />
                    <input
                        type="text"
                        placeholder="Cidade"
                        value={city}
                        onChange={(e) => setSearchParams(prev => { prev.set('city', e.target.value); return prev; })}
                        className="input"
                    />
                </div>

                <div className="filter-group">
                    <Tag className="filter-icon" />
                    <select
                        className="input"
                        value={type}
                        onChange={(e) => setSearchParams(prev => { prev.set('type', e.target.value); return prev; })}
                    >
                        <option value="">Todos os Tipos</option>
                        <option value="PRODUCT">Produtos</option>
                        <option value="SERVICE">Serviços</option>
                    </select>
                </div>

                <button type="submit" className="btn btn-primary">Buscar</button>
            </form>

            <div className="results-container">
                {loading ? (
                    <div className="loading-spinner">Buscando anúncios...</div>
                ) : ads.length > 0 ? (
                    <div className="ad-grid">
                        {ads.map((ad: any) => <AdCard key={ad.id} ad={ad} />)}
                    </div>
                ) : (
                    <div className="empty-state">
                        <p>Nenhum anúncio encontrado com esses filtros.</p>
                        <button className="btn btn-secondary mt-2" onClick={() => setSearchParams({})}>Limpar Filtros</button>
                    </div>
                )}
            </div>
        </div>
    );
};

import { useEffect, useState } from 'react';
import { Search } from 'lucide-react';
import { fetchApi } from '../utils/api';
import { AdCard } from '../components/AdCard';
import { BannerWidget } from '../components/BannerWidget';
import './Home.css';

export const Home = () => {
    const [ads, setAds] = useState([]);

    useEffect(() => {
        fetchApi('/ads?sort=recent').then(data => {
            if (data) setAds(data);
        });
    }, []);

    return (
        <div className="home-page">
            <BannerWidget position="home_topo" />

            <section className="hero-section">
                <div className="container">
                    <h1 className="hero-title">O que você está procurando hoje?</h1>
                    <div className="search-bar">
                        <input type="text" placeholder="Buscar produtos, serviços..." className="input search-input" />
                        <button className="btn btn-primary search-btn"><Search size={20} /></button>
                    </div>
                </div>
            </section>

            <div className="container mt-4">
                <h2 className="section-title">Anúncios Recentes</h2>

                <div className="ad-grid">
                    {ads.length > 0 ? (
                        ads.map((ad: any) => <AdCard key={ad.id} ad={ad} />)
                    ) : (
                        <p className="empty-state">Nenhum anúncio encontrado. Seja o primeiro a anunciar!</p>
                    )}
                </div>
            </div>

            <div className="container">
                <BannerWidget position="home_meio" />
            </div>
        </div>
    );
};

import { useState } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import { fetchApi } from '../utils/api';
import { useAuthStore } from '../store/authStore';
import './Auth.css';

export const Login = () => {
    const [email, setEmail] = useState('');
    const [password, setPassword] = useState('');
    const [error, setError] = useState('');
    const [loading, setLoading] = useState(false);

    const navigate = useNavigate();
    const login = useAuthStore(state => state.login);

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setError('');
        setLoading(true);

        try {
            const data = await fetchApi('/auth/login', {
                method: 'POST',
                body: JSON.stringify({ email, password })
            });

            if (data && data.token) {
                login(data.user, data.token);
                navigate('/dashboard');
            }
        } catch (err: any) {
            setError(err.message || 'Erro ao realizar login');
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className="auth-page container">
            <div className="auth-card box-card">
                <h1 className="auth-title">Bem-vindo de volta</h1>
                <p className="auth-subtitle">Faça login para gerenciar seus anúncios e mensagens</p>

                {error && <div className="auth-error">{error}</div>}

                <form onSubmit={handleSubmit} className="auth-form">
                    <div className="form-group">
                        <label>Email</label>
                        <input
                            type="email"
                            className="input"
                            value={email}
                            onChange={(e) => setEmail(e.target.value)}
                            required
                        />
                    </div>
                    <div className="form-group">
                        <label>Senha</label>
                        <input
                            type="password"
                            className="input"
                            value={password}
                            onChange={(e) => setPassword(e.target.value)}
                            required
                        />
                    </div>

                    <button type="submit" className="btn btn-primary auth-btn" disabled={loading}>
                        {loading ? 'Entrando...' : 'Entrar'}
                    </button>
                </form>

                <p className="auth-link">
                    Não tem uma conta? <Link to="/register">Cadastre-se</Link>
                </p>
            </div>
        </div>
    );
};

