import { useState, useEffect, useRef } from 'react';
import { useAuthStore } from '../store/authStore';
import { fetchApi, SOCKET_URL } from '../utils/api';
import { io, Socket } from 'socket.io-client';
import { Send, User as UserIcon, MessageCircle } from 'lucide-react';
import './Messages.css';

interface Message {
    id: string;
    content: string;
    sender_id: string;
    receiver_id: string;
    ad_id: string;
    created_at: string;
}

export const Messages = () => {
    const { user, token } = useAuthStore();
    const [messages, setMessages] = useState<Message[]>([]);
    const [chats, setChats] = useState<any[]>([]);
    const [activeChat, setActiveChat] = useState<any>(null);
    const [newMessage, setNewMessage] = useState('');
    const socketRef = useRef<Socket | null>(null);
    const messagesEndRef = useRef<HTMLDivElement>(null);

    useEffect(() => {
        if (!user || !token) return;

        // Fetch user's chat history
        fetchApi('/messages/conversations').then(data => {
            if (data) setChats(data);
        }).catch(() => { });

        socketRef.current = io(SOCKET_URL, {
            query: { token }
        });

        socketRef.current.on('receive_message', (msg: Message) => {
            setMessages(prev => [...prev, msg]);
            scrollToBottom();
        });

        return () => {
            socketRef.current?.disconnect();
        };
    }, [user, token]);

    const loadMessages = async (chat: any) => {
        setActiveChat(chat);
        try {
            const data = await fetchApi(`/messages/${chat.ad_id}/${chat.other_user_id}`);
            if (data) setMessages(data);
            scrollToBottom();
        } catch (error) {
            console.error(error);
        }
    };

    const sendMessage = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!newMessage.trim() || !activeChat) return;

        try {
            const tempMsg = {
                content: newMessage,
                receiver_id: activeChat.other_user_id,
                ad_id: activeChat.ad_id,
            };

            await fetchApi('/messages', {
                method: 'POST',
                body: JSON.stringify(tempMsg)
            });

            // Socket takes care of broadcasting or we just optimistically add
            setNewMessage('');
            loadMessages(activeChat); // Reload to ensure sync
        } catch (error) {
            console.error('Failed to send msg', error);
        }
    };

    const scrollToBottom = () => {
        setTimeout(() => {
            messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
        }, 100);
    };

    if (!user) return <div className="container mt-4"><h3>Por favor, faça login para ver suas mensagens.</h3></div>;

    return (
        <div className="messages-page container">
            <div className="chat-layout box-card">
                <div className="chat-sidebar">
                    <h3 className="chat-sidebar-title">Conversas</h3>
                    <div className="chat-list">
                        {chats.length === 0 ? (
                            <p className="p-3 text-light text-center">Nenhuma conversa encontrada</p>
                        ) : (
                            chats.map((chat, idx) => (
                                <div
                                    key={idx}
                                    className={`chat-item ${activeChat === chat ? 'active' : ''}`}
                                    onClick={() => loadMessages(chat)}
                                >
                                    <div className="chat-avatar">
                                        <UserIcon size={24} />
                                    </div>
                                    <div className="chat-info">
                                        <h4>{chat.other_user_name}</h4>
                                        <p>{chat.ad_title}</p>
                                    </div>
                                </div>
                            ))
                        )}
                    </div>
                </div>

                <div className="chat-window">
                    {activeChat ? (
                        <>
                            <div className="chat-header">
                                <h3>{activeChat.other_user_name}</h3>
                                <span>Ref: {activeChat.ad_title}</span>
                            </div>

                            <div className="chat-messages">
                                {messages.map((msg, idx) => (
                                    <div key={idx} className={`message-bubble ${msg.sender_id === user.id ? 'sent' : 'received'}`}>
                                        <div className="message-content">{msg.content}</div>
                                        <span className="message-time">
                                            {new Date(msg.created_at).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                                        </span>
                                    </div>
                                ))}
                                <div ref={messagesEndRef} />
                            </div>

                            <form className="chat-input-area" onSubmit={sendMessage}>
                                <input
                                    type="text"
                                    className="input"
                                    placeholder="Digite uma mensagem..."
                                    value={newMessage}
                                    onChange={(e) => setNewMessage(e.target.value)}
                                />
                                <button type="submit" className="btn btn-primary btn-icon-only">
                                    <Send size={20} />
                                </button>
                            </form>
                        </>
                    ) : (
                        <div className="chat-empty">
                            <MessageCircle className="chat-empty-icon" />
                            <p>Selecione uma conversa para começar a enviar mensagens.</p>
                        </div>
                    )}
                </div>
            </div>
        </div>
    );
};

import { useState } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import { fetchApi } from '../utils/api';
import './Auth.css';

export const Register = () => {
    const [formData, setFormData] = useState({
        name: '',
        email: '',
        password: '',
        phone: '',
        city: ''
    });
    const [error, setError] = useState('');
    const [loading, setLoading] = useState(false);

    const navigate = useNavigate();

    const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        setFormData({ ...formData, [e.target.name]: e.target.value });
    };

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setError('');
        setLoading(true);

        try {
            await fetchApi('/auth/register', {
                method: 'POST',
                body: JSON.stringify(formData)
            });
            navigate('/login');
        } catch (err: any) {
            setError(err.message || 'Erro ao realizar cadastro');
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className="auth-page container">
            <div className="auth-card box-card">
                <h1 className="auth-title">Crie sua conta</h1>
                <p className="auth-subtitle">Junte-se à nossa comunidade para comprar e vender</p>

                {error && <div className="auth-error">{error}</div>}

                <form onSubmit={handleSubmit} className="auth-form">
                    <div className="form-group">
                        <label>Nome completo</label>
                        <input
                            type="text" name="name" className="input"
                            value={formData.name} onChange={handleChange} required
                        />
                    </div>
                    <div className="form-group">
                        <label>Email</label>
                        <input
                            type="email" name="email" className="input"
                            value={formData.email} onChange={handleChange} required
                        />
                    </div>
                    <div className="form-group">
                        <label>Telefone / WhatsApp</label>
                        <input
                            type="tel" name="phone" className="input"
                            value={formData.phone} onChange={handleChange} required
                        />
                    </div>
                    <div className="form-group">
                        <label>Cidade</label>
                        <input
                            type="text" name="city" className="input"
                            value={formData.city} onChange={handleChange} required
                        />
                    </div>
                    <div className="form-group">
                        <label>Senha</label>
                        <input
                            type="password" name="password" className="input"
                            value={formData.password} onChange={handleChange} required
                        />
                    </div>

                    <button type="submit" className="btn btn-primary auth-btn" disabled={loading}>
                        {loading ? 'Cadastrando...' : 'Cadastrar'}
                    </button>
                </form>

                <p className="auth-link">
                    Já tem uma conta? <Link to="/login">Faça Login</Link>
                </p>
            </div>
        </div>
    );
};

